import base64
import pickle
import json
from datetime import datetime

def process_pubsub_message(event, context):
    """
    Cloud Function triggered by Pub/Sub messages containing pickled objects.
    Processes batch jobs from distributed task queue.
    """
    try:
        # Decode the Pub/Sub message data
        if 'data' in event:
            message_data = base64.b64decode(event['data'])
        else:
            print("No data found in message")
            return
        
        # Deserialize the pickled object
        task_data = pickle.loads(message_data)
        
        # Process the deserialized task
        process_task(task_data)
        
        print(f"Successfully processed task: {task_data.get('task_id', 'unknown')}")
        
    except Exception as e:
        print(f"Error processing message: {str(e)}")
        raise


def process_task(task_data):
    """
    Process the deserialized task data.
    """
    task_type = task_data.get('type', 'unknown')
    task_id = task_data.get('task_id', 'N/A')
    payload = task_data.get('payload', {})
    
    print(f"Processing task {task_id} of type {task_type}")
    
    if task_type == 'data_transformation':
        process_data_transformation(payload)
    elif task_type == 'batch_computation':
        process_batch_computation(payload)
    elif task_type == 'aggregation':
        process_aggregation(payload)
    elif task_type == 'model_training':
        process_model_training(payload)
    else:
        print(f"Unknown task type: {task_type}")
    
    # Log completion
    log_task_completion(task_id, task_type)


def process_data_transformation(payload):
    """Process data transformation tasks."""
    data = payload.get('data', [])
    transformation = payload.get('transformation', 'identity')
    
    print(f"Transforming {len(data)} records using {transformation}")
    
    # Example transformations
    if transformation == 'normalize':
        result = [normalize_record(record) for record in data]
    elif transformation == 'aggregate':
        result = aggregate_records(data)
    elif transformation == 'filter':
        criteria = payload.get('filter_criteria', {})
        result = [record for record in data if matches_criteria(record, criteria)]
    else:
        result = data
    
    # Store or return results
    store_results(payload.get('output_location'), result)


def process_batch_computation(payload):
    """Process batch computation tasks."""
    operation = payload.get('operation', 'sum')
    data = payload.get('data', [])
    
    print(f"Computing {operation} on batch of {len(data)} items")
    
    if operation == 'sum':
        result = sum(data)
    elif operation == 'average':
        result = sum(data) / len(data) if data else 0
    elif operation == 'max':
        result = max(data) if data else None
    elif operation == 'min':
        result = min(data) if data else None
    else:
        result = None
    
    print(f"Computation result: {result}")
    store_results(payload.get('output_location'), result)


def process_aggregation(payload):
    """Process aggregation tasks."""
    records = payload.get('records', [])
    group_by = payload.get('group_by', 'category')
    agg_function = payload.get('aggregate_function', 'count')
    
    print(f"Aggregating {len(records)} records by {group_by}")
    
    # Group records
    groups = {}
    for record in records:
        key = record.get(group_by, 'unknown')
        if key not in groups:
            groups[key] = []
        groups[key].append(record)
    
    # Apply aggregation
    result = {}
    for key, group in groups.items():
        if agg_function == 'count':
            result[key] = len(group)
        elif agg_function == 'sum':
            field = payload.get('sum_field', 'value')
            result[key] = sum(r.get(field, 0) for r in group)
        elif agg_function == 'average':
            field = payload.get('avg_field', 'value')
            values = [r.get(field, 0) for r in group]
            result[key] = sum(values) / len(values) if values else 0
    
    store_results(payload.get('output_location'), result)


def process_model_training(payload):
    """Process model training tasks."""
    model_type = payload.get('model_type', 'linear')
    training_data = payload.get('training_data', [])
    parameters = payload.get('parameters', {})
    
    print(f"Training {model_type} model with {len(training_data)} samples")
    
    # Placeholder for actual model training
    trained_model = {
        'type': model_type,
        'trained_at': datetime.now().isoformat(),
        'samples': len(training_data),
        'parameters': parameters,
        'metrics': {
            'accuracy': 0.95,
            'loss': 0.05
        }
    }
    
    store_results(payload.get('model_output_location'), trained_model)


def normalize_record(record):
    """Normalize a single record."""
    if isinstance(record, dict):
        return {k: str(v).lower().strip() if isinstance(v, str) else v 
                for k, v in record.items()}
    return record


def aggregate_records(data):
    """Simple aggregation of records."""
    if not data:
        return {}
    
    aggregated = {
        'count': len(data),
        'timestamp': datetime.now().isoformat()
    }
    
    if isinstance(data[0], dict):
        # Count unique values for each field
        for key in data[0].keys():
            values = [r.get(key) for r in data if key in r]
            aggregated[f'{key}_unique'] = len(set(values))
    
    return aggregated


def matches_criteria(record, criteria):
    """Check if record matches filter criteria."""
    for key, value in criteria.items():
        if key not in record or record[key] != value:
            return False
    return True


