def log_task_completion(task_id, task_type):
    """Log task completion for monitoring."""
    completion_log = {
        'task_id': task_id,
        'task_type': task_type,
        'completed_at': datetime.now().isoformat(),
        'status': 'success'
    }
    print(f"Task completed: {json.dumps(completion_log)}")